checker_dsl:
EXISTS (`method M`) {
  AND {
    (`method M has name "onAuthenticationSucceeded"`),
    EXISTS (`class C`) {
      AND {
        (`class C is the declaring type of method M`),
        EXISTS (`class SuperC`) {
          AND {
            (`class SuperC is a supertype (including itself) of class C`),
            OR {
              (`class SuperC has qualified name "android.hardware.fingerprint.FingerprintManager$AuthenticationCallback"`),
              (`class SuperC has qualified name "android.hardware.biometrics.BiometricPrompt$AuthenticationCallback"`),
              (`class SuperC has qualified name "androidx.biometric.BiometricPrompt$AuthenticationCallback"`)
            }
          }
        }
      }
    },
    EXISTS (`parameter P`) {
      AND {
        (`parameter P is the first parameter (index 0) of method M`),
        NOT {
          EXISTS (`variable access VA`) {
            AND {
              (`variable access VA accesses parameter P`),
              NOT {
                EXISTS (`super method call SMC`) {
                  AND {
                    (`super method call SMC is enclosed in method M`),
                    (`super method call SMC has first argument (index 0) that is parameter P`),
                    (`variable access VA is the access of parameter P in the super method call argument`),
                    EXISTS (`class DirectSuper`) {
                      AND {
                        (`class DirectSuper is a direct supertype of the declaring type of method M`),
                        OR {
                          (`class DirectSuper has qualified name "android.hardware.fingerprint.FingerprintManager$AuthenticationCallback"`),
                          (`class DirectSuper has qualified name "android.hardware.biometrics.BiometricPrompt$AuthenticationCallback"`),
                          (`class DirectSuper has qualified name "androidx.biometric.BiometricPrompt$AuthenticationCallback"`)
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
